Code:
public int countClumps(int[] nums) {
    if (nums.length == 0) {
        return 0;
    }

    int count = 0;
    int current = nums[0];
    int currentCount = 1;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == current) {
            currentCount++;
        } else {
            if (currentCount >= 2) {
                count++;
            }
            current = nums[i];
            currentCount = 1;
        }
    }

    if (currentCount >= 2) {
        count++;
    }

    return count;
}

